package edu.nyu.cs.android; // this package name should be changed in submission


import android.app.*;
import android.content.*;
import android.graphics.Bitmap;
import android.graphics.Color;
import android.net.Uri;
import android.os.Bundle;
import android.provider.MediaStore.Images;
import android.widget.ImageView;
import android.view.View;


public class FileOpener extends Activity {
	public ImageView imageView;
	private static final int REQUEST_IMAGE = 1234567890;
	
	/** Called when the activity is first created. */
    @Override 
    public void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.main);
        imageView = (ImageView) findViewById(R.id.imageView);
    }
    
    //TODO: Add code for responding to a VIEW intent for PDF and image files.  The data URI should be extracted from the intent as part of this method implementation. 
    public void onActivityResult(int requestCode, int resultCode, Intent data){
		if (requestCode == REQUEST_IMAGE && resultCode == RESULT_OK) {
			Bitmap bitmap = (Bitmap) data.getExtras().get("data");
			imageView.setImageBitmap(bitmap);
			imageView.setBackgroundColor(Color.GREEN);
			imageView.refreshDrawableState();
		}
    }
}